// --- StateStore tests ---

func TestStateStore_PutGet(t *testing.T) {
	s := NewStateStore("n1")
	s.Put("key1", []byte("value1"))
	v, ok := s.Get("key1")
	if !ok || string(v) != "value1" {
		t.Fatalf("expected (value1, true), got (%s, %v)", v, ok)
